function _safeMint(address to, uint256 id) internal virtual {
    _mint(to, id);

    require(
        to.code.length == 0 ||
            ERC721TokenReceiver(to).onERC721Received(msg.sender, address(0), id, "") ==
            ERC721TokenReceiver.onERC721Received.selector,
        "UNSAFE_RECIPIENT"
    );
}

function _safeMint(
    address to,
    uint256 id,
    bytes memory data
) internal virtual {
    _mint(to, id);

    require(
        to.code.length == 0 ||
            ERC721TokenReceiver(to).onERC721Received(msg.sender, address(0), id, data) ==
            ERC721TokenReceiver.onERC721Received.selector,
        "UNSAFE_RECIPIENT"
    );
}

function transferFrom(address src, address dst, uint rawAmount) external returns (bool) {
    address spender = msg.sender;
    uint96 spenderAllowance = allowances[src][spender];
    uint96 amount = safe96(rawAmount, "Comp::approve: amount exceeds 96 bits");

    if (spender != src && spenderAllowance != type(uint96).max) {
        uint96 newAllowance = sub96(spenderAllowance, amount, "Comp::transferFrom: transfer amount exceeds spender allowance");
        allowances[src][spender] = newAllowance;

        emit Approval(src, spender, newAllowance);
    }

    _transferTokens(src, dst, amount);
    return true;
}

function ceil(SD59x18 x) pure returns (SD59x18 result) {
    int256 xInt = x.unwrap();
    if (xInt > uMAX_WHOLE_SD59x18) {
        revert Errors.PRBMath_SD59x18_Ceil_Overflow(x);
    }

    int256 remainder = xInt % uUNIT;
    if (remainder == 0) {
        result = x;
    } else {
        unchecked {
            // Solidity uses C fmod style, which returns a modulus with the same sign as x.
            int256 resultInt = xInt - remainder;
            if (xInt > 0) {
                resultInt += uUNIT;
            }
            result = wrap(resultInt);
        }
    }
}

function getIsolationModeState(
  DataTypes.UserConfigurationMap memory self,
  mapping(address => DataTypes.ReserveData) storage reservesData,
  mapping(uint256 => address) storage reservesList
) internal view returns (bool, address, uint256) {
  if (isUsingAsCollateralOne(self)) {
    uint256 assetId = _getFirstAssetIdByMask(self, COLLATERAL_MASK);

    address assetAddress = reservesList[assetId];
    uint256 ceiling = reservesData[assetAddress].configuration.getDebtCeiling();
    if (ceiling != 0) {
      return (true, assetAddress, ceiling);
    }
  }
  return (false, address(0), 0);
}

function _calculateDebt(
  DataTypes.ReserveCache memory debtReserveCache,
  DataTypes.ExecuteLiquidationCallParams memory params,
  uint256 healthFactor
) internal view returns (uint256, uint256, uint256) {
  (uint256 userStableDebt, uint256 userVariableDebt) = Helpers.getUserCurrentDebt(
    params.user,
    debtReserveCache
  );

  uint256 userTotalDebt = userStableDebt + userVariableDebt;

  uint256 closeFactor = healthFactor > CLOSE_FACTOR_HF_THRESHOLD
    ? DEFAULT_LIQUIDATION_CLOSE_FACTOR
    : MAX_LIQUIDATION_CLOSE_FACTOR;

  uint256 maxLiquidatableDebt = userTotalDebt.percentMul(closeFactor);

  uint256 actualDebtToLiquidate = params.debtToCover > maxLiquidatableDebt
    ? maxLiquidatableDebt
    : params.debtToCover;

  return (userVariableDebt, userTotalDebt, actualDebtToLiquidate);
}

function permit(
  address owner,
  address spender,
  uint256 value,
  uint256 deadline,
  uint8 v,
  bytes32 r,
  bytes32 s
) external override {
  require(owner != address(0), Errors.ZERO_ADDRESS_NOT_VALID);
  //solium-disable-next-line
  require(block.timestamp <= deadline, Errors.INVALID_EXPIRATION);
  uint256 currentValidNonce = _nonces[owner];
  bytes32 digest = keccak256(
    abi.encodePacked(
      '\x19\x01',
      DOMAIN_SEPARATOR(),
      keccak256(abi.encode(PERMIT_TYPEHASH, owner, spender, value, currentValidNonce, deadline))
    )
  );
  require(owner == ecrecover(digest, v, r, s), Errors.INVALID_SIGNATURE);
  _nonces[owner] = currentValidNonce + 1;
  _approve(owner, spender, value);
}

function init(bytes32 ilk) external auth {
    require(ilks[ilk].rate == 0, "Vat/ilk-already-init");
    ilks[ilk].rate = 10 ** 27;
}
